package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

/**
 * A scorer that works in parallel.
 */
public class IdealParScoring extends AbstractDnaScoring {

    private int[][] S;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
        scoringRunner.start("IdealParScoring", args);
    }

    /**
     * Creates a new IdealParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public IdealParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        S = new int[xLength + 1][yLength + 1];
    }

    /**
     * This method should be filled in with a parallel implementation of the Smith-Waterman alignment algorithm that
     * maximizes ideal parallelism.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int xLen = x.length();
        final int yLen = y.length();

        // Initialize boundaries
        for (int i = 0; i <= xLen; i++) {
            S[i][0] = i * getScore(charMap(x.charAt(i - 1)), 0);
        }
        for (int j = 0; j <= yLen; j++) {
            S[0][j] = j * getScore(0, charMap(y.charAt(j - 1)));
        }

        // Process antidiagonals in parallel
        for (int d = 2; d <= xLen + yLen; d++) {
            final int diagonal = d;

            edu.rice.hj.api.HJ.finish(edu.rice.hj.api.Module.M1_0, () -> {
                for (int i = Math.max(1, diagonal - yLen); i <= Math.min(xLen, diagonal - 1); i++) {
                    final int iVal = i;
                    edu.rice.hj.api.HJ.async(edu.rice.hj.api.Module.M1_1, () -> {
                        edu.rice.hj.api.HJ.doWork(1);
                        final int j = diagonal - iVal;
                        final int diagScore = S[iVal - 1][j - 1] + getScore(charMap(x.charAt(iVal - 1)), charMap(y.charAt(j - 1)));
                        final int upScore = S[iVal - 1][j] + getScore(charMap(x.charAt(iVal - 1)), 0);
                        final int leftScore = S[iVal][j - 1] + getScore(0, charMap(y.charAt(j - 1)));
                        S[iVal][j] = Math.max(diagScore, Math.max(upScore, leftScore));
                    });
                }
            });
        }

        return S[xLen][yLen];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

/**
 * A scorer that allocates memory during computation, so that it may compute the scores for two sequences without
 * requiring O(|X||Y|) memory.
 */
public class SparseParScoring extends AbstractDnaScoring {

    private int xLen;
    private int yLen;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Creates a new SparseParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        this.xLen = xLength;
        this.yLen = yLength;
    }

    /**
     * Here you should implement a parallel version of the SW alignment algorithm that can support datasets where the
     * size of the S matrix exceeds the available memory.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        // Use 2-row rolling buffer for O(yLen) memory
        int[] prev = new int[yLen + 1];
        int[] curr = new int[yLen + 1];

        // Initialize first row boundary
        for (int j = 0; j <= yLen; j++) {
            prev[j] = j * getScore(0, charMap(y.charAt(j - 1)));
        }

        // Process each row
        for (int i = 1; i <= xLen; i++) {
            final int row = i;
            final int[] prevRow = prev;
            final int[] currRow = curr;

            // Initialize first column
            currRow[0] = row * getScore(charMap(x.charAt(row - 1)), 0);

            // Compute each cell in this row sequentially (due to left dependency)
            for (int j = 1; j <= yLen; j++) {
                final int diagScore = prevRow[j - 1] + getScore(charMap(x.charAt(row - 1)), charMap(y.charAt(j - 1)));
                final int upScore = prevRow[j] + getScore(charMap(x.charAt(row - 1)), 0);
                final int leftScore = currRow[j - 1] + getScore(0, charMap(y.charAt(j - 1)));
                currRow[j] = Math.max(diagScore, Math.max(upScore, leftScore));
            }

            // Swap rows
            int[] temp = prevRow;
            prev = currRow;
            curr = temp;
        }

        return prev[yLen];
    }

}

